// One item per eval in the queue. Composes the SendGrid payload in Phoebe Harper's
// voice (IAML Director of Operations). Mentions the program's city and the
// Block 1 instructor's first name so every message references the specific cohort.
const items = $input.all();

function escapeHtml(s) {
  return String(s == null ? '' : s)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#39;');
}

function buildSignatureHtml() {
  // Template provided by Mike, with name + title swapped for Phoebe.
  return `
<main style="font-family: Inter, Arial, sans-serif; font-size: 16px;">
  <table style="padding:0px;margin:10px 0;border:none">
    <tbody><tr>
      <td colspan="1" rowspan="1" style="vertical-align:middle;padding:10px 7px 0 0">
        <p style="line-height: 1.5;padding-left: 0px!important;">
          <img style="height: 75px;width: 75px;clear: both;" alt="Company logo" height="75"
               src="https://storage.googleapis.com/signaturesatori/customer-C043gkzsd/images/companyLogo/KBouH.png"
               width="75" title="Company logo">
        </p>
      </td>
      <td colspan="1" rowspan="1" style="border-left:3px solid #dddddd;padding:7px 0px 0px 10px;font-family:'arial','helvetica',sans-serif;font-size:12px;line-height:14px;color:#555555">
        <div style="padding-left:0px!important;margin-bottom:10px">
          <p style="line-height: 1.5;padding-left: 0px!important;">
            <strong><span style="font-size: 14px; color: rgb(255, 152, 0)">Phoebe</span> <span style="font-size: 14px; color: rgb(255, 152, 0)">Harper</span></strong><br>
            Director of Operations
          </p>
        </div>
        <div style="padding-left:0px!important;margin-bottom:10px">
          <p style="line-height: 1.5;padding-left: 0px!important;">
            <span style="color: rgb(0, 102, 255)">Phone: (949) 760-1700</span>
          </p>
        </div>
        <div style="padding-left:0px!important;margin-bottom:10px">
          <p style="line-height: 1.5;padding-left: 0px!important;">
            <strong>Institute for Applied Management &amp; Law, Inc.</strong><br>
            1024 Bayside Dr., Suite 172<br>
            Newport Beach, CA 92660<br>
            <a target="_blank" rel="noopener noreferrer nofollow" href="https://www.iaml.com">
              <span style="color: rgb(0, 102, 255)">www.iaml.com</span>
            </a>
          </p>
        </div>
      </td>
    </tr></tbody>
  </table>
</main>`;
}

function buildSignatureText() {
  return [
    '',
    'Phoebe Harper',
    'Director of Operations',
    'Phone: (949) 760-1700',
    'Institute for Applied Management & Law, Inc.',
    '1024 Bayside Dr., Suite 172',
    'Newport Beach, CA 92660',
    'www.iaml.com'
  ].join('\n');
}

return items.map(({ json: row }) => {
  const firstName      = (row.first_name || '').trim() || 'there';
  const programName    = row.program_name || 'your IAML program';
  const city           = (row.city || '').trim();
  const instructorFirst = (row.instructor_first_name || '').trim();
  const url            = `https://iaml.com/evaluation.html?token=${row.resume_token}`;
  const subject        = city
    ? `Your feedback on this week's program in ${city}`
    : `Your ${programName} evaluation`;

  // Build the "with John in Atlanta" clause conditionally so missing data
  // degrades cleanly.
  let contextClause;
  if (instructorFirst && city) {
    contextClause = `${programName} with ${instructorFirst} in ${city}`;
  } else if (city) {
    contextClause = `${programName} in ${city}`;
  } else if (instructorFirst) {
    contextClause = `${programName} with ${instructorFirst}`;
  } else {
    contextClause = programName;
  }

  const text = [
    `Hi ${firstName},`,
    '',
    `Now that you've wrapped up ${contextClause}, I'd appreciate your feedback on the program. Takes about five minutes.`,
    '',
    `Open your evaluation:`,
    url,
    '',
    'Your responses shape how we teach the next cohort, and flag anything our team should follow up on with you. The link is unique to you and saves as you go, so pause and return whenever works.',
    '',
    'Thanks,',
    buildSignatureText()
  ].join('\n');

  const html = `
<div style="font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Inter, Arial, sans-serif; max-width: 600px; margin: 0 auto; color: #1a1a2e; padding: 24px; line-height: 1.55;">
  <p style="font-size: 16px; margin: 0 0 16px;">Hi ${escapeHtml(firstName)},</p>
  <p style="font-size: 16px; margin: 0 0 16px;">Now that you&rsquo;ve wrapped up <strong>${escapeHtml(contextClause)}</strong>, I&rsquo;d appreciate your feedback on the program. Takes about five minutes.</p>
  <p style="margin: 24px 0;">
    <a href="${escapeHtml(url)}" style="display: inline-block; padding: 13px 24px; background: #188BF6; color: #ffffff; text-decoration: none; border-radius: 8px; font-weight: 600; font-size: 15px;">Open your evaluation</a>
  </p>
  <p style="font-size: 16px; margin: 0 0 16px;">Your responses shape how we teach the next cohort, and flag anything our team should follow up on with you. The link is unique to you and saves as you go, so pause and return whenever works.</p>
  <p style="font-size: 16px; margin: 0 0 8px;">Thanks,</p>
  ${buildSignatureHtml()}
</div>`;

  return {
    json: {
      evaluation_id: row.evaluation_id,
      resume_token: row.resume_token,
      email: row.email,
      first_name: row.first_name,
      last_name: row.last_name,
      program_name: row.program_name,
      instance_name: row.instance_name,
      city: row.city,
      instructor_first_name: row.instructor_first_name,
      subject,
      text,
      html
    }
  };
});

