parameters.query:
SELECT public.eval_mark_email_sent(
  '{{ $('Compose Email').item.json.evaluation_id }}'::uuid,
  FALSE,
  $err${{ $json.error?.message || $json.error || 'SendGrid call failed' }}$err$::text
);
